+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "franken_node/compatibility/dashboard/v1",
+  "title": "Compatibility Regression Dashboard",
+  "description": "Machine-readable compatibility status report.",
+  "type": "object",
+  "required": ["schema_version", "timestamp", "overall"],
+  "properties": {
+    "schema_version": {"const": "1.0"},
+    "timestamp": {"type": "string", "format": "date-time"},
+    "overall": {
+      "type": "object",
+      "required": ["total_behaviors", "tested", "passing", "failing", "pass_rate"],
+      "properties": {
+        "total_behaviors": {"type": "integer", "minimum": 0},
+        "tested": {"type": "integer", "minimum": 0},
+        "passing": {"type": "integer", "minimum": 0},
+        "failing": {"type": "integer", "minimum": 0},
+        "pass_rate": {"type": "number", "minimum": 0, "maximum": 1}
+      }
+    },
+    "by_family": {
+      "type": "array",
+      "items": {
+        "type": "object",
+        "required": ["family", "total_behaviors", "pass_rate"],
+        "properties": {
+          "family": {"type": "string"},
+          "total_behaviors": {"type": "integer"},
+          "tested": {"type": "integer"},
+          "passing": {"type": "integer"},
+          "failing": {"type": "integer"},
+          "pass_rate": {"type": "number"}
+        }
+      }
+    },
+    "by_band": {
+      "type": "array",
+      "items": {
+        "type": "object",
+        "required": ["band", "pass_rate"],
+        "properties": {
+          "band": {"type": "string", "enum": ["core", "high-value", "edge", "unsafe"]},
+          "total_fixtures": {"type": "integer"},
+          "passing": {"type": "integer"},
+          "failing": {"type": "integer"},
+          "pass_rate": {"type": "number"},
+          "target": {"type": "number"},
+          "meets_target": {"type": "boolean"}
+        }
+      }
+    },
+    "regressions": {
+      "type": "array",
+      "items": {
+        "type": "object",
+        "properties": {
+          "fixture_id": {"type": "string"},
+          "band": {"type": "string"},
+          "previously": {"type": "string"},
+          "now": {"type": "string"},
+          "first_failed": {"type": "string"}
+        }
+      }
+    }
+  },
+  "additionalProperties": false
+}

@@ -0,0 +1,74 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "franken_node/compatibility/fixture/v1",
+  "title": "Compatibility Test Fixture",
+  "description": "Defines a compatibility test case with expected canonical output.",
+  "type": "object",
+  "required": ["id", "api_family", "api_name", "band", "input", "expected_output"],
+  "properties": {
+    "id": {
+      "type": "string",
+      "pattern": "^fixture:[a-z_]+:[a-zA-Z_]+:[a-z0-9_-]+$",
+      "description": "Unique fixture ID (e.g., fixture:fs:readFile:utf8-basic)."
+    },
+    "api_family": {
+      "type": "string"
+    },
+    "api_name": {
+      "type": "string"
+    },
+    "band": {
+      "type": "string",
+      "enum": ["core", "high-value", "edge", "unsafe"]
+    },
+    "description": {
+      "type": ["string", "null"],
+      "description": "Human-readable description of what this fixture tests."
+    },
+    "input": {
+      "type": "object",
+      "description": "Input arguments and state for the fixture.",
+      "properties": {
+        "args": {
+          "type": "array",
+          "description": "Arguments to the API call."
+        },
+        "env": {
+          "type": "object",
+          "description": "Environment state required."
+        },
+        "files": {
+          "type": "object",
+          "description": "File contents to set up before execution."
+        }
+      }
+    },
+    "expected_output": {
+      "type": "object",
+      "description": "Expected canonical output.",
+      "properties": {
+        "return_value": {
+          "description": "Expected return value."
+        },
+        "error": {
+          "type": ["object", "null"],
+          "description": "Expected error if applicable."
+        },
+        "side_effects": {
+          "type": ["array", "null"],
+          "description": "Expected side effects."
+        }
+      }
+    },
+    "oracle_source": {
+      "type": ["string", "null"],
+      "description": "Runtime that produced the expected output (e.g., 'node-20.11.0')."
+    },
+    "tags": {
+      "type": "array",
+      "items": {"type": "string"},
+      "description": "Tags for filtering fixtures."
+    }
+  },
+  "additionalProperties": false
+}

